import React, { useState } from "react";
import "./App.css";


function App() {
  const [cart, setCart] = useState([]);

  const products = [
    {
      id:"1",
         name: "25*5", 
      grade:"N-35",
      price: "500" 
    },
    { 
      id: 2, 
      name: "10*2", 
      grade:"N-35",
      price: 100
     },
    {
       id: 3,
       name: "10*10*2",
      grade:"N-35",
       price: 250 
      },
         { 
          id: 4, 
      name: "5*3", 
      grade:"N-35",
      price: 100 
    },
        {
           id: 5, 
      name: "6*3", 
      grade:"N-35",
      price: 100
     },
        { 
          id: 6, 
      name: "40*10*5", 
      grade:"N-35",
      price: 100 
    },

  ];

  const addToCart = (product) => {
    setCart([...cart, product]);
  };

  return (
    <div className="container">
      <h1>Texpart</h1>

      <h2>Cart Items: {cart.length}</h2>

      <div className="products">
        {products.map((product) => (
          <div className="card" key={product.id}>
            <img src={product.image} alt={product.name} />
            <h3>{product.name}</h3>
            <p>₹{product.price}</p>

            <button onClick={() => addToCart(product)}>
              Add to Cart
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
